let sonar2 = 0
input.onButtonPressed(Button.A, function () {
    basic.showNumber(SuperBitV2_Digital.Ultrasonic(SuperBitV2_Digital.mwDigitalNum.P1P2))
    sonar2 = SuperBitV2_Digital.Ultrasonic(SuperBitV2_Digital.mwDigitalNum.P1P2)
    basic.clearScreen()
})
input.onButtonPressed(Button.AB, function () {
    if (SuperBitV2_Digital.PIR(SuperBitV2_Digital.mwDigitalNum.P7P8, SuperBitV2_Digital.enPIR.OPIR)) {
        basic.showNumber(0)
    } else {
        basic.showNumber(1)
    }
})
input.onButtonPressed(Button.B, function () {
    basic.showNumber(SuperBitV2_Analog.Potentiometer(SuperBitV2_Analog.mwAnalogNum.AP0P3))
})
input.onLogoEvent(TouchButtonEvent.Touched, function () {
    basic.showString("R")
    basic.showNumber(Module_World_Color.GetRGBValue(Module_World_Color.enGetRGB.GetValueR))
    basic.showString("G")
    basic.showNumber(Module_World_Color.GetRGBValue(Module_World_Color.enGetRGB.GetValueG))
    basic.showString("B")
    basic.showNumber(Module_World_Color.GetRGBValue(Module_World_Color.enGetRGB.GetValueB))
})
input.onGesture(Gesture.ThreeG, function () {
    if (SuperBitV2_Analog.Rocker(SuperBitV2_Analog.mwAnalogNum2.AP1P2, SuperBitV2_Analog.enRocker.Up)) {
        basic.showLeds(`
            . . # . .
            . # # # .
            # . # . #
            . . # . .
            . . # . .
            `)
    } else if (SuperBitV2_Analog.Rocker(SuperBitV2_Analog.mwAnalogNum2.AP1P2, SuperBitV2_Analog.enRocker.Down)) {
        basic.showLeds(`
            . . # . .
            . . # . .
            # . # . #
            . # # # .
            . . # . .
            `)
    } else if (SuperBitV2_Analog.Rocker(SuperBitV2_Analog.mwAnalogNum2.AP1P2, SuperBitV2_Analog.enRocker.Right)) {
        basic.showLeds(`
            . . # . .
            . . . # .
            # # # # #
            . . . # .
            . . # . .
            `)
    } else if (SuperBitV2_Analog.Rocker(SuperBitV2_Analog.mwAnalogNum2.AP1P2, SuperBitV2_Analog.enRocker.Left)) {
        basic.showLeds(`
            . . # . .
            . # . . .
            # # # # #
            . # . . .
            . . # . .
            `)
    }
    basic.clearScreen()
})
